{
  "parameters": "z.object({ material: z.string().describe("The block type to use, e.g., 'oak_planks'"), count: z.number().int().positive().describe("Total number of blocks to place"), startPosition: z.object({ x: z.number(), y: z.number().optional().describe("The starting height; defaults to bot's current elevation if omitted"), z: z.number() }).describe("The base coordinates to start building the barricade") })",
  "executionArgs": {
    "material": "oak_planks",
    "count": 8,
    "startPosition": {
      "x": 5,
      "z": 5
    }
  },
  "code": "const normalizeItemName = function (value) {
  return value.trim().toLowerCase().replace(/^minecraft:/, '').replace(/\\s+/g, '_');
};
const requestedMaterial = normalizeItemName(args.material);
const findMaterialItem = function () {
  return bot.inventory.items().find(function (item) {
    return normalizeItemName(item.name) === requestedMaterial || (typeof item.displayName === 'string' && normalizeItemName(item.displayName) === requestedMaterial);
  });
};
const startY = typeof args.startPosition.y === 'number' ? args.startPosition.y : Math.floor(bot.entity.position.y);
const materialItem = findMaterialItem();
if (!materialItem) {
  return "<NO MATERIAL>: I don't have any " + args.material + " in my inventory.";
}
startBackgroundSkill(bot, 'build_barricade', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  const sleep = function (ms) { return new Promise(function (resolve) { setTimeout(resolve, ms); }); };
  const canContinue = function () { return !token.cancelled && bot.health > 0 && Boolean(bot.entity); };
  for (let i = 0; i < args.count; i++) {
    if (!canContinue()) break;
    const currentMaterial = findMaterialItem();
    if (!currentMaterial) {
      console.log('Out of material, stopping barricade.');
      break;
    }
    const dx = Math.floor(i / 2);
    const dy = i % 2;
    const targetPos = new Vec3(args.startPosition.x + dx, startY + dy, args.startPosition.z);
    if (bot.blockAt(targetPos).name !== 'air') continue;
    try {
      const goal = new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, 3);
      await bot.pathfinder.goto(goal);
      if (!canContinue()) break;
      const neighbors = [
        new Vec3(0, -1, 0),
        new Vec3(0, 0, 1),
        new Vec3(0, 0, -1),
        new Vec3(1, 0, 0),
        new Vec3(-1, 0, 0)
      ];
      let referenceBlock = null;
      let faceVector = null;
      for (const offset of neighbors) {
        const neighborPos = targetPos.plus(offset);
        const block = bot.blockAt(neighborPos);
        if (block && block.name !== 'air' && block.name !== 'water' && block.name !== 'lava') {
          referenceBlock = block;
          faceVector = offset.scaled(-1);
          break;
        }
      }
      if (referenceBlock) {
        await bot.equip(currentMaterial, 'hand');
        if (!bot.physicsEnabled) {
            while (!bot.physicsEnabled && canContinue()) { await sleep(50); }
        }
        await bot.lookAt(referenceBlock.position.plus(new Vec3(0.5, 0.5, 0.5)));
        await bot.placeBlock(referenceBlock, faceVector);
        await sleep(200);
      } else {
        console.log('Could not find neighbor to place block at ' + targetPos);
      }
    } catch (err) {
      console.log('Error placing block at ' + targetPos + ': ' + err.message);
    }
  }
});
return "<BARRICADING>: Starting to build a " + args.count + "-block " + args.material + " barricade at (" + args.startPosition.x + ", " + startY + ", " + args.startPosition.z + ").";"
}

